OUTPUT_RE = re.compile(r'''^\s*(?:
    Status:|Name:|ID:|Agent:|Assigned\ to:|Task\ Completed|Crew\ Execution|
    Compiled\ successfully!|You\ can\ now\ view|Local:|On\ Your\ Network:|API\ 文档:|后端\ API:|服务地址:|
    🚀|🤖|🧠|📋|✅|⚠️|📝
)''', re.X)

CODE_CUE_RE = re.compile(r'(代码|示例|如下|命令|启动|配置项|文件结构|目录结构|项目结构|输出|运行|执行|终端|Makefile|环境变量|核心方法|关键配置|服务地址)[:：]?\s*$')


def normalize_code_line(line: str) -> str:
    s = line.strip()
    s = s.replace('“', '"').replace('”', '"').replace('‘', "'").replace('’', "'")
    s = s.replace('…', '...')
    # OCR often turns CLI double hyphen into an en dash.
    s = re.sub(r'(?<=\s)–(?=[A-Za-z])', '--', s)
    s = re.sub(r'(?<=\s)—(?=[A-Za-z])', '--', s)
    return s


def is_heading(line: str) -> bool:
    return bool(re.match(r'^\s{0,3}#{1,6}\s+', line))


def raw_kind(line: str, next_line: str = '') -> str | None:
    s = line.strip()
    if not s:
        return None
    if line.startswith('```') or IMAGE_RE.match(s):
        return None
    if TREE_RE.match(line):
        return 'text'
    if PATH_ROOT_RE.match(line) and next_line and TREE_RE.match(next_line):
        return 'text'
    if BOX_RE.search(line) and (line.lstrip().startswith(('│', '╭', '╰', '└', '├')) or '─' in line):
        return 'text'
    if CMD_RE.match(line) or PROMPT_RE.match(line):
        return 'bash'
    if ENV_RE.match(line):
        return 'dotenv'
    if OUTPUT_RE.match(line):
        return 'text'
    if CODE_START_RE.match(line):
        return 'code'
    return None


def is_continuation(line: str, block_lang: str) -> bool:
    s = line.strip()
    if not s:
        return True
    if IMAGE_RE.match(s) or is_heading(line):
        return False
    if block_lang == 'text':
        return bool(TREE_RE.match(line) or BOX_RE.search(line) or OUTPUT_RE.match(line) or PATH_ROOT_RE.match(line))
    if block_lang == 'bash':
        return bool(CMD_RE.match(line) or PROMPT_RE.match(line) or OUTPUT_RE.match(line) or ENV_RE.match(line))
    if block_lang == 'dotenv':
        return bool(ENV_RE.match(line) or re.match(r'^\s*#', line))
    return bool(raw_kind(line) or CONT_RE.match(line))


def choose_lang(lines: list[str], initial: str) -> str:
    joined = '\n'.join(lines)
    if initial == 'text':
        return 'text'
    if initial == 'bash':
        return 'bash'
    if initial == 'dotenv':
        return 'dotenv'
    if re.search(r'\b(from|import|def|class|self|elif|except|async\s+def)\b', joined):
        # JSX/JS also uses import; React markers win below.
        if re.search(r'\bReact\b|<[A-Z][A-Za-z0-9_]*|\bconst\b|\blet\b|=>', joined):
            return 'jsx'
        return 'python'
    if re.search(r'\b(function|const|let|var|export|=>|axios|React|useState)\b|<[A-Z][A-Za-z0-9_]*', joined):
        return 'jsx'
    if re.search(r'\b(SELECT|WITH|CREATE|INSERT|UPDATE|DELETE|ALTER|DROP)\b', joined):
        return 'sql'
    if re.search(r'\b(package|func|fmt\.|context\.)\b', joined):
        return 'go'
    return 'text'


def format_code_lines(lines: list[str], lang: str) -> list[str]:
    raw = [normalize_code_line(x) for x in lines if x.strip()]
    if lang in {'text', 'dotenv', 'bash', 'sql'}:
        return raw

    unit = '  ' if lang in {'jsx', 'javascript', 'js', 'go'} else '    '
    out: list[str] = []
    indent = 0
    paren_depth = 0
    for original in raw:
        s = original.strip()
        if not s:
            continue
        low = s.lstrip()
        # Dedent obvious closers before printing.
        if re.match(r'^(\}|\)|\]|</|except\b|elif\b|else\b|finally\b|catch\b)', low):
            indent = max(0, indent - 1)
        out.append(unit * indent + s)

        # Adjust indentation. This is intentionally conservative and aimed at readability,
        # not producing executable code from partial snippets.
        opens = s.count('(') + s.count('[') + s.count('{')
        closes = s.count(')') + s.count(']') + s.count('}')
        if s.endswith(':') or s.endswith('{'):
            indent += 1
        elif opens > closes and not s.endswith(';'):
            indent += min(opens - closes, 1)
        elif closes > opens:
            indent = max(0, indent - min(closes - opens, 1))
        paren_depth += opens - closes
    return out


def should_start_block(lines: list[str], i: int) -> tuple[str, int] | None:
    line = lines[i]
    next_line = lines[i + 1] if i + 1 < len(lines) else ''
    kind = raw_kind(line, next_line)
    if not kind:
        return None

    # Single prose-looking API references are better left as text unless introduced by a code cue.
    prev = ''
    j = i - 1
    while j >= 0 and not lines[j].strip():
        j -= 1
    if j >= 0:
        prev = lines[j].strip()
    if kind == 'code' and not CODE_CUE_RE.search(prev):
        # Still allow unmistakable language starts.
        if not re.match(r'^\s*(from|import|class|def|function|const|let|var|@[A-Za-z_]|<[A-Z]|SELECT|CREATE|INSERT|UPDATE|DELETE)\b', line):
            return None
    return (kind, i)


def transform(text: str) -> str:
    lines = text.splitlines()
    out: list[str] = []
    i = 0
    in_fence = False
    while i < len(lines):
        line = lines[i]
        if line.startswith('```'):
            in_fence = not in_fence
            out.append(line.rstrip())
            i += 1
            continue
        if in_fence:
            out.append(line.rstrip())
            i += 1
            continue

        if line.strip() == 'unpreview':
            i += 1
            continue

        m = HEADING_NO_SPACE.match(line)
        if m:
            out.append(f'{m.group(1)} {m.group(2).strip()}')
            i += 1
            continue

        # Fix numbered list spacing such as 1.Python -> 1. Python.
        m = NUMBER_NO_SPACE.match(line)
        if m and not re.match(r'^\d+\.\d+', line):
            out.append(f'{m.group(1)}. {m.group(2).strip()}')
            i += 1
            continue

        start = should_start_block(lines, i)
        if start:
            initial = start[0]
            block: list[str] = []
            j = i
            blank_buffer: list[str] = []
            while j < len(lines):
                cur = lines[j]
                if cur.startswith('```'):
                    break
                if not cur.strip():
                    blank_buffer.append(cur)
                    # allow OCR blank lines inside code only when the next nonblank still belongs.
                    k = j + 1
                    while k < len(lines) and not lines[k].strip():
                        k += 1
                    if k < len(lines) and is_continuation(lines[k], initial):
                        j += 1
                        continue
                    break
                if block and not is_continuation(cur, initial):
                    break
                if not block and not raw_kind(cur, lines[j + 1] if j + 1 < len(lines) else ''):
                    break
                block.append(cur)
                j += 1

            nonblank_count = sum(1 for x in block if x.strip())
            if nonblank_count >= 2 or initial in {'bash', 'dotenv'} or (nonblank_count == 1 and CODE_CUE_RE.search((out[-1] if out else ''))):
                lang = choose_lang(block, initial)
                formatted = format_code_lines(block, lang)
                if formatted:
                    if out and out[-1].strip():
                        out.append('')
                    out.append(f'```{lang}')
                    out.extend(formatted)
                    out.append('```')
                    i = j
                    continue

        out.append(line.rstrip())
        i += 1

    # Collapse excessive blank lines outside fences.
    compact: list[str] = []
    fence = False
    blanks = 0
    for line in out:
        if line.startswith('```'):
            fence = not fence
            compact.append(line)
            blanks = 0
            continue
        if not fence and not line.strip():
            blanks += 1
            if blanks <= 1:
                compact.append('')
            continue
        blanks = 0
        compact.append(line.rstrip())

    return '\n'.join(compact).rstrip() + '\n'


def main() -> int:
    changed = False
    for arg in sys.argv[1:]:
        path = Path(arg)
        old = path.read_text(encoding='utf-8')
        new = transform(old)
        if new != old:
            path.write_text(new, encoding='utf-8')
            print(path)
            changed = True
    return 0 if changed else 1

if __name__ == '__main__':
    raise SystemExit(main())
